import { useCallback, useEffect, useState } from 'react';
import { getCodeReplacePending, type CodeReplacePending } from '../services/master/codeReplace';

export type CodeReplacePendingMap = Map<string, CodeReplacePending>;

/** Pending/replace jobs keyed by oldCode (uppercase). */
export function useCatalogCodeReplacePending(catalogKind?: string, reloadKey = 0) {
  const [pendingMap, setPendingMap] = useState<CodeReplacePendingMap>(new Map());
  const [loading, setLoading] = useState(false);

  const refresh = useCallback(async () => {
    if (!catalogKind) {
      setPendingMap(new Map());
      return;
    }
    setLoading(true);
    try {
      const rows = await getCodeReplacePending(catalogKind);
      const map = new Map<string, CodeReplacePending>();
      rows.forEach(r => map.set(r.oldCode.toUpperCase(), r));
      setPendingMap(map);
    } catch {
      setPendingMap(new Map());
    } finally {
      setLoading(false);
    }
  }, [catalogKind]);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      if (!catalogKind) return;
      setLoading(true);
      getCodeReplacePending(catalogKind)
        .then(rows => {
          if (cancelled) return;
          const map = new Map<string, CodeReplacePending>();
          rows.forEach(r => map.set(r.oldCode.toUpperCase(), r));
          setPendingMap(map);
        })
        .catch(() => { if (!cancelled) setPendingMap(new Map()); })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [catalogKind, reloadKey]);

  const getForCode = useCallback(
    (code: string) => pendingMap.get(code.trim().toUpperCase()),
    [pendingMap],
  );

  return { pendingMap, loading, refresh, getForCode };
}
