import type { CSSProperties } from 'react';

/** Apply BE `fontColor` / `backgroundColor` on catalog grid cells when present. */
export function resolveCatalogRowCellStyle(
  row: Record<string, unknown>,
): CSSProperties | undefined {
  const bg =
    typeof row.backgroundColor === 'string' && row.backgroundColor.trim()
      ? row.backgroundColor
      : undefined;
  const fg =
    typeof row.fontColor === 'string' && row.fontColor.trim() ? row.fontColor : undefined;
  if (!bg && !fg) return undefined;
  return { backgroundColor: bg, color: fg };
}
