import { normalizeCode, normalizeCodeOptional } from '../../utils/codeField';
import type {
  CreateMaterialGroupRequest,
  MaterialGroupDto,
  UpdateMaterialGroupRequest,
} from './models';

/** True when group has no parent (root / level 1). */
export function isRootMaterialGroup(parentId?: string): boolean {
  return !parentId;
}

export function toCreateMaterialGroupPayload(
  form: Partial<MaterialGroupDto>,
): CreateMaterialGroupRequest {
  const root = isRootMaterialGroup(form.parentId);
  return {
    code: normalizeCode(form.code!),
    name: form.name!.trim(),
    parentId: form.parentId || undefined,
    isActive: form.isActive ?? true,
    accountCode: root ? normalizeCodeOptional(form.accountCode) : undefined,
  };
}

export function toUpdateMaterialGroupPayload(
  form: Partial<MaterialGroupDto>,
): UpdateMaterialGroupRequest {
  const root = isRootMaterialGroup(form.parentId);
  return {
    name: form.name!.trim(),
    parentId: form.parentId || undefined,
    isActive: form.isActive ?? true,
    accountCode: root ? normalizeCodeOptional(form.accountCode) : undefined,
  };
}
